    try:
        Version(text); print('accepted')
    except InvalidVersion:
        print('InvalidVersion')

from minipackaging import SpecifierSet, InvalidSpecifier
for text in ['=>1.0', '>=', '==1.*.2']:
    try:
        SpecifierSet(text); print('accepted')
    except InvalidSpecifier:
        print('InvalidSpecifier')

from minipackaging import Requirement, InvalidRequirement
for text in ['bad name>=1', 'pkg[bad extra]', 'pkg @ https://x >=1']:
    try:
        Requirement(text); print('accepted')
    except InvalidRequirement:
        print('InvalidRequirement')

from minipackaging import Marker, InvalidMarker, UndefinedEnvironmentName
try:
    Marker('python_version === "3"'); print('accepted')
except InvalidMarker:
    print('InvalidMarker')
try:
    Marker('python_version >= "3.8"').evaluate({}); print('evaluated')
except UndefinedEnvironmentName:
    print('UndefinedEnvironmentName')
